import React, {useEffect, useState} from 'react'
import styled from 'styled-components'
import {getUserProfile} from '../WebAPI'
import {useDispatch, useSelector, accountSelector} from 'react-redux'
import {setProfileUpdateActive} from '../redux/accountSlice'


const ProfileWrapper = styled.div `

`


const Section = styled.div `
display:flex;
margin:20px 0;
align-items:center;
`


const Title = styled.div `
font-size:0.9rem;
letter-spacing:5px;
width:200px;
color:grey;
font-weight:900;
`

const Div = styled.div `
height:30px;
width:500px;
color:grey;
box-sizing:border-box;
font-size:1rem;
&:focus {
	outline: none !important;
}
`

const Input = styled.input `
height:30px;
width:400px;
color:grey;
height:30px;
border:1px solid rgb(230, 230, 230);
border-radius:8px;
padding:0 10px;
box-sizing:border-box;
font-size:0.8rem;
&:focus {
	outline: none !important;
}
`

const Text = styled.textarea `
width:500px;
color:grey;
font-size:0.8rem;
height:60px;
border:1px solid rgb(230, 230, 230);
border-radius:8px;
padding:5px 10px;
font-family:YuGothic;
box-sizing:border-box;
&:focus {
	outline: none !important;
}
`

const BtnSection = styled.div `
display:flex;
align-items:center;
justify-content:center;
`

const Btn = styled.div `
text-align:center;
line-height:40px;
width:200px;
height:40px;
background-color:#1C1C1C;
border-radius:7px;
border:1.5px solid #1C1C1C;
color:white;
font-size:0.9rem;
margin:30px 30px;
&:hover {
	cursor:pointer;
	background-color:white;
	color:#1C1C1C;
	border:1.5px solid #1C1C1C;
}
`

export default function MeProfile () {
	const [userProfile, setUserProfile] = useState([{}])
	const dispatch = useDispatch()

	const [username, setUsername] = useState(null)
	const [email, setEmail] = useState(null)
	const [bio, setBio] = useState(null)
	const [profileUpdateActive, setProfileUpdateActive] = useState(false)

	useEffect(() => {
		getUserProfile(localStorage.getItem('userId'), setUserProfile)
		setUsername(userProfile.username)
		setEmail(userProfile.email)
		setBio(userProfile.bio)
	},[userProfile.username])

	console.log(userProfile)
	const onUsernameChange = e => {
		setUsername(e.target.value)
	}

	const onEmailChange = e => {
		setEmail(e.target.value)
	}

	const onBioChange = e => {
		setBio(e.target.value)
	}

	const onProfileUpdate = () => {
		dispatch(setProfileUpdateActive())
	}

	return (
		<ProfileWrapper>
			<Section>
				<Title>USERNAME</Title>
				{profileUpdateActive? <Input onChange={onUsernameChange} value={username}/> : <Div>{userProfile.username}</Div>}
			</Section>
			<Section>
				<Title>EMAIL</Title>
				{profileUpdateActive? <Input onChange={onEmailChange} value={email}/> : <Div>{userProfile.email}</Div>}
			</Section>
			<Section>
				<Title>BIO</Title>
				{profileUpdateActive? <Text onChange={onBioChange} value={bio}/> : <Div>{userProfile.bio}</Div>}
			</Section>
			<BtnSection>
				<Btn onClick={onProfileUpdate}>EDIT PROFILE</Btn>
				<Btn>CHANGE PASSWORD</Btn>
			</BtnSection>
		</ProfileWrapper>
	)
}

